import React, { useState } from "react";
import "./Auth.css";
import axios from "axios";

const NewPrediction = () => {

  const [form, setForm] = useState({
    Gender: "",
    Education_Level: "",
    Qualification: "",
    Experience: "",
    JobRole: "",
    PrimarySkill: "",
    Location: ""
  });

  const [salary, setSalary] = useState("");

  const handleNewPrediction = () => {
  setForm({
    Gender: "",
    Education_Level: "",
    Qualification: "",
    Experience: "",
    JobRole: "",
    PrimarySkill: "",
    Location: ""
  });

  setSalary(""); 
};
const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔥 PREDICT API
  const handlePredict = async (e) => {
    e.preventDefault();

    try {
      const user = JSON.parse(localStorage.getItem("user"));

      if (!user) {
        alert("User not logged in");
        return;
      }

      const response = await axios.post(
        "http://localhost:5000/predict",
        {
          ...form,
          userEmail: user.email  
        }
      );

      const predictedSalary = response.data.salary;
      setSalary(predictedSalary);

      
      let count = localStorage.getItem("predictionCount") || 0;
      count = parseInt(count) + 1;
      localStorage.setItem("predictionCount", count);

      localStorage.setItem("lastSalary", predictedSalary);

      let history = JSON.parse(localStorage.getItem("history")) || [];
      history.push({ ...form, salary: predictedSalary });
      localStorage.setItem("history", JSON.stringify(history));

    } catch (error) {
      console.error("Prediction error:", error);
      alert("Prediction failed. Check backend.");
    }
  };

  const qualificationOptions = {
    Diploma: ["Diploma in Computer Engineering", "Diploma in IT"],
    Bachelor: ["BCA", "B.Tech / B.E", "B.Sc", "BBA", "B.Com"],
    Master: ["MCA", "MSc CS", "MBA", "M.E/M.Tech"],
    PhD: ["PhD CS", "PhD AI"]
  };
  const jobSkillMap = {
  IT: {
    roles: [
      "Software Engineer",
      "Frontend Developer",
      "Backend Developer",
      "Full Stack Developer",
      "Data Scientist",
      "Machine Learning Engineer",
      "DevOps Engineer",
      "Cloud Engineer",
      "Cybersecurity Analyst",
      "Mobile App Developer",
      "Data Engineer"
    ],
    skills: [
      "Java",
      "Python",
      "JavaScript",
      "React",
      "Node.js",
      "SQL",
      "MongoDB",
      "AWS",
      "Docker",
      "Kubernetes",
      "TensorFlow",
      "PyTorch"
    ]
  },

  NON_IT: {
    roles: [
      "HR Executive",
      "Finance Analyst",
      "Marketing Executive",
      "Sales Manager",
      "Business Analyst",
      "Operations Manager",
      "Customer Support Executive"
    ],
    skills: [
      "Communication",
      "Excel",
      "Financial Analysis",
      "Digital Marketing",
      "CRM",
      "Leadership",
      "Sales Strategy"
    ]
  }
};

  return (
    <div className="prediction-wrapper">
      <div className="prediction-card">

        <h1 className="title">💼 Salary Prediction</h1>

        <form onSubmit={handlePredict} className="form-grid">

          <div className="form-group">
            <label>Gender</label>
            <select name="Gender" value={form.Gender} onChange={handleChange} required>
              <option value="">Select Gender</option>
              <option>Male</option>
              <option>Female</option>
              <option>Other</option>
            </select>
          </div>

          <div className="form-group">
            <label>Education Level</label>
            <select name="Education_Level" value={form.Education_Level} onChange={handleChange} required>
              <option value="">Select Education</option>
              <option>Diploma</option>
              <option>Bachelor</option>
              <option>Master</option>
              <option>PhD</option>
            </select>
          </div>

          <div className="form-group">
            <label>Qualification</label>
            <select name="Qualification" value={form.Qualification} onChange={handleChange} required>
              <option value="">Select Qualification</option>
              {form.Education_Level &&
                qualificationOptions[form.Education_Level].map((course, i) => (
                  <option key={i}>{course}</option>
                ))}
            </select>
          </div>

          <div className="form-group">
            <label>Experience (Years)</label>
            <input
              type="number"
              name="Experience"
              value={form.Experience}
              onChange={handleChange}
              placeholder="Enter years"
              required
            />
          </div>

          
    <select name="Category" value={form.Category} onChange={handleChange} required>
  <option value="">Select Category</option>
  <option value="IT">IT</option>
  <option value="NON_IT">Non-IT</option>
</select>
         <select name="JobRole" value={form.JobRole} onChange={handleChange} required>
  <option value="">Select Role</option>

  {form.Category &&
    jobSkillMap[form.Category].roles.map((role, i) => (
      <option key={i}>{role}</option>
    ))}
</select>
          <button type="submit" className="predict-btn">
            Predict Salary
          </button>

        </form>

        {salary && (
  <div className="result-box">
    <h3>Predicted Salary</h3>
    <p>₹ {salary}</p>

    
    <button 
      className="new-btn"
      onClick={handleNewPrediction}
    >
      + New Prediction
    </button>
  </div>
)}
      </div>
    </div>
  );
};

export default NewPrediction;
